import{_ as e,o as t,c as r,ae as o}from"./chunks/framework.D6sYw4vw.js";const p=JSON.parse('{"title":"碳中和与能源相关开源软件工具","description":"","frontmatter":{},"headers":[],"relativePath":"awesome-carbon-neutrality/RenewableEnergy/index.md","filePath":"awesome-carbon-neutrality/RenewableEnergy/index.md","lastUpdated":1773144464000}'),l={name:"awesome-carbon-neutrality/RenewableEnergy/index.md"};function n(i,a,h,s,d,u){return t(),r("div",null,[...a[0]||(a[0]=[o('<p>@def title = &quot;碳中和相关开源软件汇编&quot; @def hascode = true @def date = Date(2021, 11, 19) @def rss = &quot;碳中和相关开源软件汇编&quot; @def tags = [&quot;open source&quot;, &quot;energy&quot; , &quot;carbon neutrality&quot;]</p><h1 id="碳中和与能源相关开源软件工具" tabindex="-1">碳中和与能源相关开源软件工具 <a class="header-anchor" href="#碳中和与能源相关开源软件工具" aria-label="Permalink to &quot;碳中和与能源相关开源软件工具&quot;">​</a></h1><h2 id="太阳能" tabindex="-1">太阳能 <a class="header-anchor" href="#太阳能" aria-label="Permalink to &quot;太阳能&quot;">​</a></h2><ul><li><p><strong>SAM与ssc</strong> —由美国能源部委托美国国家可再生能源实验室（NREL）开发的可再生能源项目评估模型软件。可针对光伏、光热、风力、地热、生物质等几种可再生能源的发电成本及系统发电特性进行计算。 <a href="./sam-ssc.html">点击查看详细介绍</a></p></li><li><p><strong>REopt_Lite_API</strong> —美国国家可再生能源实验室（NREL）开发可再生能源系统优化软件。程序采用的是用基于python的django框架提供网页建模界面，生成的优化问题以json形式描述，通过http api调用JuMP进行优化问题求解。使用了docker-compose来实现建模和优化的连接。JuMP.jl（Julia Math Program）是Julia语言的数学规划建模平台。<a href="https://github.com/NREL/REopt_Lite_API" target="_blank" rel="noreferrer">点击访问REopt_Lite_API源码</a></p></li></ul><h2 id="风能" tabindex="-1">风能 <a class="header-anchor" href="#风能" aria-label="Permalink to &quot;风能&quot;">​</a></h2><h2 id="储能" tabindex="-1">储能 <a class="header-anchor" href="#储能" aria-label="Permalink to &quot;储能&quot;">​</a></h2><h3 id="电池储能" tabindex="-1">电池储能 <a class="header-anchor" href="#电池储能" aria-label="Permalink to &quot;电池储能&quot;">​</a></h3><h3 id="氢储能" tabindex="-1">氢储能 <a class="header-anchor" href="#氢储能" aria-label="Permalink to &quot;氢储能&quot;">​</a></h3><h2 id="能源管理系统" tabindex="-1">能源管理系统 <a class="header-anchor" href="#能源管理系统" aria-label="Permalink to &quot;能源管理系统&quot;">​</a></h2><h2 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h2><ul><li><strong>CoolProp</strong> —开源的物性数据库，C++编写，MIT许可证。有Python、Matlab、Modelica、Java接口，也能够通过Excel、FORTRAN、Javascript、PHP、Mathematica、Julia、Labview、EES等访问。难能可贵的是，CoolProp还提供了<a href="https://www.nist.gov/srd/refprop" target="_blank" rel="noreferrer">NIST的REFPROP</a>的接口。换言之，可以通过CoolProp的python接口访问REFPROP的所有功能。<a href="http://coolprop.org/" target="_blank" rel="noreferrer">点击访问CoolProp官方网站</a>。我们写了一个<a href="./coolprop-intro.html">CoolProp的简单介绍</a>。</li></ul>',11)])])}const f=e(l,[["render",n]]);export{p as __pageData,f as default};
